/*
* Show or hide Fuel field with Vessel Type
* by Ana Castillo
*/
if (this.YQP_TYPE_VESSEL == null) {
    return "NO";
} else {
    return "YES";
}

/*
* Show or hide Propulsion field with Fuel field
* by Ana Castillo
*/
if (this.YQP_FUEL == null) {
    return "NO";
} else {
    return "YES";
}

/*
* Calc Age with Year field
* by Ana Castillo
*/
if (this.YQP_YEAR != "" && this.YQP_YEAR != null) {
    var currentYear = new Date().getFullYear();
    var year = this.YQP_YEAR;
    var age = currentYear - year;
    return age;
}

/*
* Calc the length with unit field
* by Ana Castillo
*/
let unit = this.YQP_UNIT;
if (unit == "Meter") {
    //Calc from meters to feets
    var feetCalc = this.YQP_LENGTH * 3.28084;
    return feetCalc.toFixed(2);
} else {
    return this.YQP_LENGTH;
}

/*
* Show or hide Exchange Rate field with Currency
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //If it is not USD show
    if (this.YQP_CURRENCY != "USD") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Specify Port with Location Mooring port
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Location Mooring port is Other
    if (this.YQP_LOCATION_MOORING_PORT == "Other") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Loss Payee Name field with Loss Payee
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Los payee is YES
    if (this.YQP_LOSS_PAYEE == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Claims Text field with Claims
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Claims is YES
    if (this.YQP_CLAIMS == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Mooring port field with Location Mooring port
* by Ana Castillo
*/
//It is Submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Location mooring port is not null and not empty and not Other
    if (this.YQP_LOCATION_MOORING_PORT != "" && 
        this.YQP_LOCATION_MOORING_PORT != null &&
        this.YQP_LOCATION_MOORING_PORT != "Other") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Sum Insured and deductible fields with Product field
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //The Product has an option with HULL
    if (this.YQP_PRODUCT.split("HULL").length > 1) {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

let typeVessel = this.YQP_OPEN_OPTIONS_YACHT_INFORMATION.YQP_TYPE_VESSEL;
var entities = [
        ['amp', '&'],
        ['apos', '\''],
        ['#x27', '\''],
        ['#x2F', '/'],
        ['#39', '\''],
        ['#47', '/'],
        ['lt', '<'],
        ['gt', '>'],
        ['nbsp', ' '],
        ['quot', '"']
    ];

for (let i = 0, max = entities.length; i < max; ++i) 
    typeVessel = typeVessel.replace(new RegExp('&'+entities[i][0]+';', 'g'), entities[i][1]);

return typeVessel;

/*
* Calc Get the user id of the request 
* by Helen Callisaya
*/
return this._user.id;

/*
* Calc Show request error
* by Helen Callisaya
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERRORS.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == null || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

/*
* Calc Get the user fullname of the request 
* by Helen Callisaya
*/
return this._user.fullname;

/*
* Calc convert Fuel value
* by Helen Callisaya
*/
let fuel = this.YQP_OPEN_OPTIONS_YACHT_INFORMATION.YQP_FUEL;
var entities = [
        ['amp', '&'],
        ['apos', '\''],
        ['#x27', '\''],
        ['#x2F', '/'],
        ['#39', '\''],
        ['#47', '/'],
        ['lt', '<'],
        ['gt', '>'],
        ['nbsp', ' '],
        ['quot', '"']
    ];

for (let i = 0, max = entities.length; i < max; ++i) 
    fuel = fuel.replace(new RegExp('&'+entities[i][0]+';', 'g'), entities[i][1]);

return fuel;

/*
* Calc convert Propulsion value
* by Helen Callisaya
*/
let propulsion = this.YQP_OPEN_OPTIONS_YACHT_INFORMATION.YQP_PROPULSION;
var entities = [
        ['amp', '&'],
        ['apos', '\''],
        ['#x27', '\''],
        ['#x2F', '/'],
        ['#39', '\''],
        ['#47', '/'],
        ['lt', '<'],
        ['gt', '>'],
        ['nbsp', ' '],
        ['quot', '"']
    ];

for (let i = 0, max = entities.length; i < max; ++i) 
    propulsion = propulsion.replace(new RegExp('&'+entities[i][0]+';', 'g'), entities[i][1]);

return propulsion;

var submitVariables = new Object();
submitVariables['SHOW'] = "YES";
submitVariables['REQUIRED'] = "YES";
console.log(this.YQP_PRODUCT.split("PI"));
if (this.YQP_PRODUCT.split("PI").length > 1) {
    submitVariables['SHOW'] = "YES";
    if (this.YQP_SUBMIT_SAVE == "SUBMIT") {   
        submitVariables['REQUIRED'] = "YES";    
    } else {
        submitVariables['REQUIRED'] = "NO";
    }
} else {
    submitVariables['SHOW'] = "NO";
    submitVariables['REQUIRED'] = "NO";
}
return submitVariables;

/*
* Set Name Button Submit
* by Helen Callisaya
*/
if (this.END_CASE_CAN_CONTINUE) {
    return 'Change Filter';
} else {
    return 'Change Information';
}

/*
* Calc Check if the variable exists
* by Helen Callisaya
*/
if (this.END_CASE_CAN_CONTINUE) {
    return 'YES';
} else {
    return 'NO';
}

